 41→const modelCache = new Map<string, ModelType>();
 42→const blpCache = new Map<string, ImageData[]>();
 43→
 44→function normalizeTextureName(textureImage: string): string {
 45→  const normalized = textureImage.replaceAll('\\', '/');
 46→  const lastSlash = normalized.lastIndexOf('/');
 47→  return (lastSlash >= 0 ? normalized.slice(lastSlash + 1) : normalized).toLowerCase();
 48→}
 49→
 50→function getTexturePath(textureImage: string, race: Race): string | null {
 51→  const key = normalizeTextureName(textureImage);
 52→  const raceTexture = HERO_PORTRAIT_CONFIG[race].textures[key];
 53→  if (raceTexture) return raceTexture;
 54→
 55→  if (key.startsWith('teamcolor')) return '/models/hero-portrait/textures/shared/TeamColor00.blp';
 56→  if (key.startsWith('teamglow')) return '/models/hero-portrait/textures/shared/TeamGlow00.blp';
 57→  return null;
 58→}
 59→
 60→async function loadModel(race: Race): Promise<ModelType> {
 61→  const path = HERO_PORTRAIT_CONFIG[race].modelPath;
 62→  const cached = modelCache.get(path);
 63→  if (cached) return cached;
 64→
 65→  const res = await fetch(path);
 66→  if (!res.ok) throw new Error(`Failed to load hero portrait model: ${path}`);
 67→  const ab = await res.arrayBuffer();
 68→  const model = parseMDX(ab);
 69→  modelCache.set(path, model);
 70→  return model;
 71→}
 72→
 73→async function loadBLPMips(path: string): Promise<ImageData[]> {
 74→  const cached = blpCache.get(path);
 75→  if (cached) return cached;
 76→
 77→  const res = await fetch(path);
 78→  if (!res.ok) throw new Error(`Failed to load hero portrait texture: ${path}`);
 79→  const ab = await res.arrayBuffer();
 80→  const blp = decodeBLP(ab);
 81→
 82→  const mips: ImageData[] = [];
 83→  const maxLevels = Math.max(1, Math.floor(Math.log2(Math.max(blp.width, blp.height))) + 1);
 84→  for (let i = 0; i < maxLevels; i++) {
 85→    const w = blp.width >> i;
 86→    const h = blp.height >> i;
 87→    if (w <= 0 || h <= 0) break;
 88→    try {
 89→      const img = getBLPImageData(blp, i);
 90→      if (!img || !img.width || !img.height) break;
 91→      mips.push(new ImageData(img.data, img.width, img.height));
 92→      if (img.width === 1 && img.height === 1) break;
 93→    } catch {
 94→      break;
 95→    }
 96→  }
 97→
 98→  if (mips.length === 0) {
 99→    throw new Error(`No mip levels decoded for hero portrait texture: ${path}`);
100→  }

