 50→function getTexturePath(textureImage: string, race: Race): string | null {
 51→  const key = normalizeTextureName(textureImage);
 52→  const raceTexture = HERO_PORTRAIT_CONFIG[race].textures[key];
 53→  if (raceTexture) return raceTexture;
 54→
 55→  if (key.startsWith('teamcolor')) return '/models/hero-portrait/textures/shared/TeamColor00.blp';
 56→  if (key.startsWith('teamglow')) return '/models/hero-portrait/textures/shared/TeamGlow00.blp';
 57→  return null;
