110→function findIdleSequenceIndex(model: ModelType, race: Race): number {
111→  const sequences = model.Sequences || [];
112→  if (sequences.length === 0) return 0;
113→
114→  const sequenceNames = sequences.map((seq) => (seq.Name || '').toLowerCase());
115→  const preferencesByRace: Record<Race, readonly string[]> = {
116→    Human: [
117→      'stand work',
118→      'stand lumber',
119→      'stand ready',
120→      'stand gold',
121→      'stand - 3',
122→      'stand -3',
123→      'stand 2',
124→      'stand - 2',
125→      'stand',
126→    ],
127→    Orc: [
128→      'stand ready',
129→      'stand - stretch',
130→      'stand - itch head',
131→      'stand - talk gesture',
132→      'stand 2',
133→      'stand - 2',
134→      'stand',
135→    ],
136→    NightElf: [
137→      'stand ready',
138→      'stand - 3',
139→      'stand -3',
140→      'stand 2',
141→      'stand - 2',
142→      'stand',
143→    ],
144→    Undead: [
145→      'stand work',
146→      'stand 2',
147→      'stand - 2',
148→      'stand ready',
149→      'stand',
150→    ],
151→  };
152→  const preferences = preferencesByRace[race];
153→
154→  for (const pref of preferences) {
155→    const idx = sequenceNames.findIndex((name) => name.includes(pref));
156→    if (idx >= 0) return idx;
157→  }
158→
159→  const fallback = sequenceNames.findIndex(
160→    (name) => name.includes('stand') && !name.includes('death') && !name.includes('decay'),
161→  );
162→  return fallback >= 0 ? fallback : 0;
163→}
