24→// Loading bar state
25→export function createLoadingBar() {
26→  const [progress, setProgress] = createSignal(0);
27→  let interval: ReturnType<typeof setInterval> | null = null;
28→
29→  function start() {
30→    setProgress(0);
31→    if (interval) clearInterval(interval);
32→    interval = setInterval(() => {
33→      setProgress(prev => {
34→        const next = prev + Math.random() * 8 + 2;
35→        if (next >= 100) {
36→          clearInterval(interval!);
37→          interval = null;
38→          setTimeout(() => {
39→            setProgress(0);
40→            setTimeout(() => start(), 100);
41→          }, 1500);
42→          return 100;
43→        }
44→        return next;
45→      });
46→    }, 400);
47→  }
48→
49→  function stop() {
50→    if (interval) {
51→      clearInterval(interval);
52→      interval = null;
53→    }
54→  }
55→
56→  return { progress, start, stop };
