164→async function loadModel(race: Race): Promise<ModelType> {
165→  const cached = modelCache.get(race);
166→  if (cached) return cached;
167→  const res = await fetch(getModelPath(race));
168→  if (!res.ok) throw new Error(`Failed to fetch clock model for ${race}`);
169→  const ab = await res.arrayBuffer();
170→  const model = parseMDX(ab);
171→  disableBackdropQuads(model);
172→  modelCache.set(race, model);
173→  return model;
174→}
