210→export default function TimeIndicatorModel(props: TimeIndicatorModelProps) {
211→  let canvasRef!: HTMLCanvasElement;
212→  const [status, setStatus] = createSignal('init');
213→  const [widgetMaskUrl, setWidgetMaskUrl] = createSignal('');
214→  let gl: WebGLRenderingContext | WebGL2RenderingContext | null = null;
215→  let modelRenderer: ModelRenderer | null = null;
216→  let rafId = 0;
217→  let resizeObserver: ResizeObserver | null = null;
218→  let disposed = false;
219→  let initVersion = 0;
220→  let viewMinX = 0;
221→  let viewMaxX = 1;
222→  let viewMinY = 0;
223→  let viewMaxY = 1;
224→
225→  const mvMatrix = mat4.create();
226→  const pMatrix = mat4.create();
227→
228→  const destroyRenderer = () => {
229→    if (!modelRenderer) return;
230→    try {
231→      modelRenderer.destroy();
232→    } catch (err) {
233→      console.warn('clock renderer destroy failed', err);
234→    } finally {
235→      modelRenderer = null;
236→    }
237→  };
238→
239→  const resizeCanvas = () => {
240→    if (!canvasRef || !gl) return;
241→    const dpr = window.devicePixelRatio || 1;
242→    const w = Math.max(1, Math.round(canvasRef.clientWidth * dpr));
243→    const h = Math.max(1, Math.round(canvasRef.clientHeight * dpr));
244→    if (canvasRef.width !== w || canvasRef.height !== h) {
245→      canvasRef.width = w;
246→      canvasRef.height = h;
247→    }
248→    gl.viewport(0, 0, w, h);
249→  };
250→
251→  const startRenderLoop = () => {
252→    const startTs = performance.now();
253→    const tick = (now: number) => {
254→      if (disposed) return;
255→      rafId = requestAnimationFrame(tick);
256→      if (!gl) return;
257→      if (!modelRenderer) {
258→        setStatus('waiting renderer');
259→        return;
260→      }
261→
262→      resizeCanvas();
263→      const frame = ((now - startTs) * 1.0) % 60000;
264→      modelRenderer.setSequence(0);
265→      modelRenderer.setFrame(frame);
266→      modelRenderer.update(0);
267→
268→      mat4.identity(mvMatrix);
269→      const baseW = Math.max(1e-6, viewMaxX - viewMinX);
270→      const baseH = Math.max(1e-6, viewMaxY - viewMinY);
271→      const cx = (viewMinX + viewMaxX) * 0.5;
272→      const cy = (viewMinY + viewMaxY) * 0.5;
273→      const canvasAspect = Math.max(1e-6, canvasRef.clientWidth / Math.max(1, canvasRef.clientHeight));
274→      const modelAspect = baseW / baseH;
275→      let viewW = baseW * 1.04;
276→      let viewH = baseH * 1.04;
277→      if (canvasAspect > modelAspect) {
278→        viewW = viewH * canvasAspect;
279→      } else {
280→        viewH = viewW / canvasAspect;
281→      }
282→      mat4.ortho(pMatrix, cx - viewW * 0.5, cx + viewW * 0.5, cy - viewH * 0.5, cy + viewH * 0.5, -10, 10);
283→      gl.clearColor(0, 0, 0, 0);
284→      gl.clear(gl.COLOR_BUFFER_BIT | gl.DEPTH_BUFFER_BIT);
285→      modelRenderer.render(mvMatrix, pMatrix, { env: false, wireframe: false });
286→      setStatus('rendering');
287→    };
288→    rafId = requestAnimationFrame(tick);
289→  };
290→
291→  const initForRace = async (race: Race) => {
292→    const version = ++initVersion;
293→    setStatus(`loading model: ${race}`);
294→    const model = await loadModel(race);
295→    if (disposed || version !== initVersion) return;
296→
297→    destroyRenderer();
298→    modelRenderer = new ModelRenderer(model);
299→    modelRenderer.initGL(gl!);
300→    modelRenderer.setCamera(vec3.fromValues(0, 0, 2), quat.fromValues(0, 0, 0, 1));
301→    modelRenderer.setLightPosition(vec3.fromValues(0, 0, 2));
302→    modelRenderer.setLightColor(vec3.fromValues(1, 1, 1));
303→    setStatus(`model loaded: ${race}`);
304→
305→    const bounds = computeVisibleBounds2D(model);
306→    if (bounds) {
307→      viewMinX = bounds.minX;
308→      viewMaxX = bounds.maxX;
309→      viewMinY = bounds.minY;
310→      viewMaxY = bounds.maxY;
311→    } else {
312→      const extMin = model.Info?.MinimumExtent;
313→      const extMax = model.Info?.MaximumExtent;
314→      if (extMin && extMax) {
315→        viewMinX = extMin[0];
316→        viewMaxX = extMax[0];
317→        viewMinY = extMin[1];
318→        viewMaxY = extMax[1];
319→      }
320→    }
321→
322→    const texturePromises = (model.Textures || []).map(async (tex) => {
323→      const path = getClockTexturePath(tex.Image, race);
324→      if (!path) return;
325→      const mips = await loadBLPMips(path);
326→      if (!disposed && version === initVersion) {
327→        modelRenderer!.setTextureImageData(tex.Image, mips);
328→      }
329→    });
330→    const [maskUrl] = await Promise.all([
331→      loadWidgetMaskDataUrl(race),
332→      Promise.all(texturePromises),
333→    ]);
334→    if (disposed || version !== initVersion) return;
335→    setWidgetMaskUrl(maskUrl);
336→    modelRenderer.setSequence(0);
337→    setStatus(`textures bound: ${race}`);
338→  };
339→
340→  onMount(() => {
341→    gl = canvasRef.getContext('webgl2', {
342→      alpha: true,
343→      premultipliedAlpha: false,
344→      antialias: true,
345→      depth: true,
346→      stencil: false,
347→    }) as WebGL2RenderingContext | null;
348→    if (!gl) {
349→      gl = canvasRef.getContext('webgl', {
350→        alpha: true,
351→        premultipliedAlpha: false,
352→        antialias: true,
353→        depth: true,
354→        stencil: false,
355→      });
356→    }
357→    if (!gl) {
358→      setStatus('no webgl context');
359→      return;
360→    }
361→
362→    setStatus('gl context ok');
363→    resizeCanvas();
364→    resizeObserver = new ResizeObserver(() => resizeCanvas());
365→    resizeObserver.observe(canvasRef);
366→    startRenderLoop();
367→    void initForRace(props.race);
368→  });
369→
370→  createEffect(() => {
371→    const race = props.race;
372→    if (!gl) return;
373→    void initForRace(race);
374→  });
375→
376→  onCleanup(() => {
377→    disposed = true;
378→    initVersion++;
379→    cancelAnimationFrame(rafId);
380→    resizeObserver?.disconnect();
381→    destroyRenderer();
382→  });
383→
384→  return (
385→    <>
386→      <canvas
387→        ref={canvasRef}
388→        style={{
389→          position: 'absolute',
390→          inset: '0',
391→          width: '100%',
392→          height: '100%',
393→          display: 'block',
394→          'pointer-events': 'none',
395→          'mask-image': widgetMaskUrl() ? `url("${widgetMaskUrl()}")` : 'none',
396→          '-webkit-mask-image': widgetMaskUrl() ? `url("${widgetMaskUrl()}")` : 'none',
397→          'mask-repeat': 'no-repeat',
398→          '-webkit-mask-repeat': 'no-repeat',
399→          'mask-size': '100% 100%',
400→          '-webkit-mask-size': '100% 100%',
401→          'mask-position': 'center',
402→          '-webkit-mask-position': 'center',
403→        }}
404→      />
405→    </>
406→  );
407→}
