import { onMount, type JSX } from 'solid-js';
import type { Renderer } from '../renderer/Renderer';
import GlueButton from './GlueButton';

interface Props {
  frameSrc: string;
  bgPath: string;
  borderPath: string;
  bgDownPath?: string;
  borderDownPath?: string;
  hoverPath?: string;
  children: JSX.Element;
  renderer: Renderer;
}

export default function MenuButton(props: Props) {
  let frameRef!: HTMLImageElement;

  onMount(() => {
    props.renderer.glueMenuFrames.push({
      ref: () => frameRef,
      imgSrc: props.frameSrc,
    });
  });

  return (
    <div class="glue-menu-slot">
      <img ref={frameRef} src={props.frameSrc} alt="" />
      <GlueButton
        bgPath={props.bgPath}
        borderPath={props.borderPath}
        bgDownPath={props.bgDownPath}
        borderDownPath={props.borderDownPath}
        hoverPath={props.hoverPath}
        renderer={props.renderer}
      >
        {props.children}
      </GlueButton>
    </div>
  );
}

