     1→import type { Race, TextureEntry } from '../lib/types';
     2→import { GLContext } from './GLContext';
     3→import { TextureManager } from './TextureManager';
     4→import { QuadBatcher } from './QuadBatcher';
     5→import { BlendManager } from './BlendManager';
     6→import { drawNineSlice } from './NineSlice';
     7→import { loadRaceTextures, preloadAllRaces, type RaceTextures } from './textures';
     8→import { RACE_PREFIXES } from '../state/race';
     9→
    10→// ─── Element Registry Types ─────────────────────────────────
    11→export interface CheckboxReg {
    12→  ref: () => HTMLElement;
    13→  visualRef: () => HTMLElement;
    14→  checked: () => boolean;
    15→}
    16→
    17→export interface RadioReg {
    18→  ref: () => HTMLElement;
    19→  visualRef: () => HTMLElement;
    20→  selected: () => boolean;
    21→}
    22→
    23→export interface SliderReg {
    24→  ref: () => HTMLElement;
    25→  value: () => number;
    26→}
    27→
    28→export interface EditBoxReg {
    29→  ref: () => HTMLElement;
    30→}
    31→
    32→export interface GlueButtonReg {
    33→  ref: () => HTMLElement;
    34→  hovered: () => boolean;
    35→  pressed: () => boolean;
    36→  disabled: boolean;
    37→  bgPath: string;
    38→  borderPath: string;
    39→  bgDownPath?: string;
    40→  borderDownPath?: string;
    41→  hoverPath?: string;
    42→}
    43→
    44→export interface GlueMenuFrameReg {
    45→  ref: () => HTMLElement;
    46→  imgSrc: string;
    47→}
    48→
    49→export interface OptionButtonReg {
    50→  ref: () => HTMLElement;
    51→  hovered: () => boolean;
    52→}
    53→
    54→export interface TooltipReg {
    55→  ref: () => HTMLElement;
    56→}
    57→
    58→export interface StatBarReg {
    59→  ref: () => HTMLElement;
    60→  fillPercent: () => number;
    61→  type: 'health' | 'mana' | 'xp' | 'build';
    62→  hasBorder: boolean;
    63→}
    64→
    65→export interface LoadingBarReg {
    66→  ref: () => HTMLElement;
    67→  fillRef: () => HTMLElement;
    68→  fillPercent: () => number;
    69→}
    70→
    71→export interface MenuPanelReg {
    72→  ref: () => HTMLElement;
    73→}
    74→
    75→export interface UpperButtonReg {
    76→  ref: () => HTMLElement;
    77→  race: Race;
    78→  hovered: () => boolean;
    79→  pressed: () => boolean;
    80→}
    81→
    82→export interface ResourceIconReg {
    83→  ref: () => HTMLElement;
    84→  type: 'gold' | 'lumber' | 'supply';
    85→}
    86→
    87→export class Renderer {
    88→  ctx = new GLContext();
    89→  texManager = new TextureManager();
    90→  batcher = new QuadBatcher();
    91→  blend = new BlendManager();
    92→
    93→  raceTex!: RaceTextures;
    94→  private skyScrollTime = 0;
    95→  private rafId = 0;
    96→  private viewportRef: (() => HTMLElement) | null = null;
    97→
    98→  // Element registries
    99→  checkboxes: CheckboxReg[] = [];
   100→  radios: RadioReg[] = [];
   101→  sliders: SliderReg[] = [];
   102→  editBoxes: EditBoxReg[] = [];
   103→  glueButtons: GlueButtonReg[] = [];
   104→  glueMenuFrames: GlueMenuFrameReg[] = [];
   105→  optionButtons: OptionButtonReg[] = [];
   106→  tooltips: TooltipReg[] = [];
   107→  statBars: StatBarReg[] = [];
   108→  loadingBars: LoadingBarReg[] = [];
   109→  menuPanels: MenuPanelReg[] = [];
   110→  upperButtons: UpperButtonReg[] = [];
   111→  resourceIcons: ResourceIconReg[] = [];
   112→
   113→  init(canvas: HTMLCanvasElement) {
   114→    this.ctx.init(canvas);
   115→    this.texManager.init(this.ctx.gl);
   116→    this.batcher.init(this.ctx);
   117→    this.blend.init(this.ctx, this.batcher);
   118→    // Wire texManager into ctx for QuadBatcher's whiteTex access
   119→    (this.ctx as any)._texManager = this.texManager;
   120→  }
   121→
   122→  setViewportRef(ref: () => HTMLElement) {
   123→    this.viewportRef = ref;
   124→  }
   125→
   126→  loadRace(race: Race) {
   127→    this.raceTex = loadRaceTextures(race, this.texManager);
   128→  }
   129→
   130→  preloadAll() {
   131→    preloadAllRaces(this.texManager);
   132→  }
   133→
   134→  start() {
   135→    const loop = (_timestamp: number) => {
   136→      this.rafId = requestAnimationFrame(loop);
   137→      this.renderFrame();
   138→    };
   139→    this.rafId = requestAnimationFrame(loop);
   140→  }
   141→
   142→  destroy() {
   143→    cancelAnimationFrame(this.rafId);
   144→    this.ctx.destroy();
   145→  }
   146→
   147→  private renderFrame() {
   148→    const { ctx, batcher, blend } = this;
   149→    const gl = ctx.gl;
   150→    if (ctx.canvasW === 0 || ctx.canvasH === 0) return;
   151→    if (!this.raceTex) return;
   152→
   153→    gl.clearColor(0, 0, 0, 0);
   154→    gl.clear(gl.COLOR_BUFFER_BIT | gl.STENCIL_BUFFER_BIT);
   155→
   156→    blend.useProgram(ctx.quadProg);
   157→    gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   158→    gl.uniform1i(ctx.quadLocs.tex, 0);
   159→    gl.uniform1i(ctx.quadLocs.alphaMode, 0);
   160→    blend.setBlend('BLEND');
   161→    batcher.batchTex = null;
   162→
   163→    const vw = ctx.canvasW / 100;
   164→    const topHudH = 4 * vw;
   165→    const hudBarH = parseFloat(getComputedStyle(document.documentElement).getPropertyValue('--hud-height')) || 240;
   166→
   167→    this.renderTopHud(vw, topHudH);
   168→    this.renderBottomHud(hudBarH);
   169→    this.renderUpperButtons();
   170→    this.renderResourceIcons();
   171→
   172→    // Viewport scissor
   173→    if (this.viewportRef) {
   174→      const vp = this.viewportRef();
   175→      if (vp) {
   176→        const vpRect = vp.getBoundingClientRect();
   177→        gl.enable(gl.SCISSOR_TEST);
   178→        gl.scissor(
   179→          vpRect.left * ctx.dpr,
   180→          (ctx.canvasH - vpRect.bottom) * ctx.dpr,
   181→          vpRect.width * ctx.dpr,
   182→          vpRect.height * ctx.dpr
   183→        );
   184→        this.renderViewportComponents(vpRect);
   185→        gl.disable(gl.SCISSOR_TEST);
   186→      }
   187→    }
   188→
   189→    batcher.flush();
   190→  }
   191→
   192→  private renderTopHud(vw: number, topHudH: number) {
   193→    const { ctx, batcher, blend, raceTex } = this;
   194→    const gl = ctx.gl;
   195→
   196→    const t1w = 32 * vw;
   197→    batcher.drawQuad(0, 0, t1w, topHudH, raceTex.topTile1, 0, 0, 1, 1);
   198→    const t2w = 10.875 * vw;
   199→    batcher.drawQuad(t1w, 0, t2w, topHudH, raceTex.topTile2, 0, 0, 0.34, 1);
   200→    const centerGap = ctx.canvasW - (32 + 10.875 + 6.625 + 32 + 4) * vw;
   201→    const rightStart = (32 + 10.875) * vw + centerGap;
   202→    const t3w = 6.625 * vw;
   203→    batcher.drawQuad(rightStart, 0, t3w, topHudH, raceTex.topTile2, 0.793, 0, 1, 1);
   204→    const t4w = 32 * vw;
   205→    batcher.drawQuad(rightStart + t3w, 0, t4w, topHudH, raceTex.topTile3, 0, 0, 1, 1);
   206→    const t5w = 4 * vw;
   207→    batcher.drawQuad(rightStart + t3w + t4w, 0, t5w, topHudH, raceTex.topTile4, 0, 0, 1, 1);
   208→
   209→    // Time indicator is rendered by the dedicated MDX clock component.
   210→  }
   211→
   212→  private renderBottomHud(hudBarH: number) {
   213→    const { ctx, batcher, raceTex } = this;
   214→    const y = ctx.canvasH - hudBarH;
   215→    const total = 1600;
   216→    const w1 = (512 / total) * ctx.canvasW;
   217→    const w2 = (512 / total) * ctx.canvasW;
   218→    const w3 = (512 / total) * ctx.canvasW;
   219→    const w4 = (64 / total) * ctx.canvasW;
   220→    batcher.drawQuad(0, y, w1, hudBarH, raceTex.hudTile1, 0, 0, 1, 1);
   221→    batcher.drawQuad(w1, y, w2, hudBarH, raceTex.hudTile2, 0, 0, 1, 1);
   222→    batcher.drawQuad(w1 + w2, y, w3, hudBarH, raceTex.hudTile3, 0, 0, 1, 1);
   223→    batcher.drawQuad(w1 + w2 + w3, y, w4, hudBarH, raceTex.hudTile4, 0, 0, 1, 1);
   224→  }
   225→
   226→  private renderUpperButtons() {
   227→    const { batcher, blend, ctx, raceTex } = this;
   228→    const gl = ctx.gl;
   229→
   230→    for (const btn of this.upperButtons) {
   231→      const el = btn.ref();
   232→      if (!el) continue;
   233→      const rect = el.getBoundingClientRect();
   234→      if (rect.width === 0) continue;
   235→
   236→      const atlasPath = `war3/Widgets/Console/${btn.race}/${RACE_PREFIXES[btn.race].lower}-console-buttonstates2.png`;
   237→      const atlasEntry = this.texManager.load(atlasPath);
   238→
   239→      const u0 = 0, u1 = 0.664;
   240→      let v0 = 0, v1 = 0.172;
   241→      if (btn.pressed()) { v0 = 0.25; v1 = 0.422; }
   242→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, atlasEntry, u0, v0, u1, v1);
   243→
   244→      if (btn.hovered() && !btn.pressed()) {
   245→        batcher.flush();
   246→        blend.setBlend('ADD');
   247→        batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, atlasEntry, u0, 0.75, u1, 0.922);
   248→        batcher.flush();
   249→        blend.setBlend('BLEND');
   250→        batcher.batchTex = null;
   251→      }
   252→    }
   253→  }
   254→
   255→  private renderResourceIcons() {
   256→    const { batcher, raceTex } = this;
   257→    for (const icon of this.resourceIcons) {
   258→      const el = icon.ref();
   259→      if (!el) continue;
   260→      const rect = el.getBoundingClientRect();
   261→      if (rect.width === 0) continue;
   262→      let texEntry: TextureEntry;
   263→      if (icon.type === 'gold') texEntry = raceTex.gold;
   264→      else if (icon.type === 'lumber') texEntry = raceTex.lumber;
   265→      else texEntry = raceTex.supply;
   266→      batcher.drawQuad(rect.left, rect.top, rect.width, rect.height, texEntry, 0, 0, 1, 1);
   267→    }
   268→  }
   269→
   270→  private renderViewportComponents(vpRect: DOMRect) {
   271→    const { ctx, batcher, blend } = this;
   272→    const gl = ctx.gl;
   273→
   274→    blend.useProgram(ctx.quadProg);
   275→    gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
   276→    gl.uniform1i(ctx.quadLocs.tex, 0);
   277→    gl.uniform1i(ctx.quadLocs.alphaMode, 0);
   278→    batcher.batchTex = null;
   279→
   280→    this.renderGlueButtons(vpRect);
   281→    this.renderEscMenuComponents(vpRect);
   282→    this.renderTooltips(vpRect);
   283→    this.renderBars(vpRect);
   284→    this.renderLoadingBars(vpRect);
   285→    this.renderMenuPanels(vpRect);
   286→  }
   287→
   288→  private isVisible(rect: DOMRect, vpRect: DOMRect): boolean {
   289→    return rect.width > 0 && rect.bottom >= vpRect.top && rect.top <= vpRect.bottom;
   290→  }
   291→
   292→  private renderGlueButtons(vpRect: DOMRect) {
   293→    const { ctx, batcher, blend, raceTex, texManager } = this;
   294→    const gl = ctx.gl;
   295→
   296→    for (const btn of this.glueButtons) {
   297→      const el = btn.ref();
   298→      if (!el) continue;
   299→      const rect = el.getBoundingClientRect();
   300→      if (!this.isVisible(rect, vpRect)) continue;
   301→
   302→      let bgPath: string, borderPath: string;
   303→      if (btn.disabled) {
   304→        bgPath = btn.bgPath;
   305→        borderPath = btn.borderPath;
   306→      } else if (btn.pressed() && btn.bgDownPath) {
   307→        bgPath = btn.bgDownPath;
   308→        borderPath = btn.borderDownPath || btn.borderPath;
   309→      } else {
   310→        bgPath = btn.bgPath;
   311→        borderPath = btn.borderPath;
   312→      }
   313→
   314→      const bgEntry = texManager.loadRepeat(bgPath);
   315→      const borderEntry = borderPath ? texManager.load(borderPath) : null;
   316→      const corner = borderEntry && borderEntry.loaded
   317→        ? Math.floor(Math.min(borderEntry.width / 8, rect.height * 0.35))
   318→        : Math.floor(rect.height * 0.35);
   319→      const inset = Math.round(corner * 0.25);
