     1→import type { GLContext } from './GLContext';
     2→import type { QuadBatcher } from './QuadBatcher';
     3→
     4→export type BlendMode = 'BLEND' | 'ADD' | 'NONE';
     5→
     6→export class BlendManager {
     7→  private current: BlendMode | '' = '';
     8→  private ctx!: GLContext;
     9→  private batcher!: QuadBatcher;
    10→  currentProg: WebGLProgram | null = null;
    11→
    12→  init(ctx: GLContext, batcher: QuadBatcher) {
    13→    this.ctx = ctx;
    14→    this.batcher = batcher;
    15→  }
    16→
    17→  setBlend(mode: BlendMode) {
    18→    if (mode === this.current) return;
    19→    this.batcher.flush();
    20→    this.current = mode;
    21→    const gl = this.ctx.gl;
    22→    switch (mode) {
    23→      case 'BLEND':
    24→        gl.enable(gl.BLEND);
    25→        gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
    26→        break;
    27→      case 'ADD':
    28→        gl.enable(gl.BLEND);
    29→        gl.blendFunc(gl.SRC_ALPHA, gl.ONE);
    30→        break;
    31→      case 'NONE':
    32→        gl.disable(gl.BLEND);
    33→        break;
    34→    }
    35→  }
    36→
    37→  useProgram(prog: WebGLProgram) {
    38→    if (prog !== this.currentProg) {
    39→      this.batcher.flush();
