     1→import type { TextureEntry } from '../lib/types';
     2→import type { GLContext } from './GLContext';
     3→import type { QuadBatcher } from './QuadBatcher';
     4→import type { BlendManager } from './BlendManager';
     5→
     6→export function drawNineSlice(
     7→  ctx: GLContext,
     8→  batcher: QuadBatcher,
     9→  blend: BlendManager,
    10→  x: number, y: number, w: number, h: number,
    11→  borderEntry: TextureEntry | null,
    12→  cornerSize: number,
    13→  tiledBgEntry: TextureEntry | null,
    14→  tileSize: number,
    15→  inset?: number
    16→) {
    17→  if (!borderEntry || !borderEntry.loaded) return;
    18→  const gl = ctx.gl;
    19→  const atlasW = borderEntry.width;
    20→  const cellW = atlasW / 8;
    21→  const cs = cornerSize;
    22→  const ins = inset || 0;
    23→
    24→  function cellUV(idx: number): [number, number, number, number] {
    25→    const u0 = (idx * cellW) / atlasW;
    26→    const u1 = ((idx + 1) * cellW) / atlasW;
    27→    return [u0, 0, u1, 1];
    28→  }
    29→
    30→  // Tiled background
    31→  if (tiledBgEntry && tiledBgEntry.loaded) {
    32→    batcher.flush();
    33→    blend.useProgram(ctx.tiledProg);
    34→    gl.uniform2f(ctx.tiledLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
    35→    gl.uniform1i(ctx.tiledLocs.tex, 0);
    36→    gl.uniform2f(ctx.tiledLocs.quadSize, w - ins * 2, h - ins * 2);
    37→    gl.uniform2f(ctx.tiledLocs.tileSize, tileSize, tileSize);
    38→    gl.uniform1i(ctx.tiledLocs.alphaMode, 0);
    39→    blend.setBlend('BLEND');
    40→    batcher.batchTex = null;
    41→    batcher.drawQuad(x + ins, y + ins, w - ins * 2, h - ins * 2, tiledBgEntry, 0, 0, 1, 1);
    42→    batcher.flush();
    43→    blend.useProgram(ctx.quadProg);
    44→    gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
    45→    gl.uniform1i(ctx.quadLocs.tex, 0);
    46→    gl.uniform1i(ctx.quadLocs.alphaMode, 0);
    47→    batcher.batchTex = null;
    48→  }
    49→
    50→  blend.setBlend('BLEND');
    51→
    52→  // Corners
    53→  const [u4a, v4a, u4b, v4b] = cellUV(4);
    54→  batcher.drawQuad(x, y, cs, cs, borderEntry, u4a, v4a, u4b, v4b);
    55→  const [u5a, v5a, u5b, v5b] = cellUV(5);
    56→  batcher.drawQuad(x + w - cs, y, cs, cs, borderEntry, u5a, v5a, u5b, v5b);
    57→  const [u6a, v6a, u6b, v6b] = cellUV(6);
    58→  batcher.drawQuad(x, y + h - cs, cs, cs, borderEntry, u6a, v6a, u6b, v6b);
    59→  const [u7a, v7a, u7b, v7b] = cellUV(7);
    60→  batcher.drawQuad(x + w - cs, y + h - cs, cs, cs, borderEntry, u7a, v7a, u7b, v7b);
    61→
    62→  // Vertical edges
    63→  const edgeH = h - cs * 2;
    64→  if (edgeH > 0) {
    65→    const [u0a, v0a, u0b, v0b] = cellUV(0);
    66→    batcher.drawQuad(x, y + cs, cs, edgeH, borderEntry, u0a, v0a, u0b, v0b);
    67→    const [u1a, v1a, u1b, v1b] = cellUV(1);
    68→    batcher.drawQuad(x + w - cs, y + cs, cs, edgeH, borderEntry, u1a, v1a, u1b, v1b);
    69→  }
    70→
    71→  // Horizontal edges (rotated)
    72→  const edgeW = w - cs * 2;
    73→  if (edgeW > 0) {
    74→    const [u2a, v2a, u2b, v2b] = cellUV(2);
