export type Race = 'Human' | 'Orc' | 'NightElf' | 'Undead';

export interface RacePrefix {
  tile: string;
  esc: string;
  lower: string;
  display: string;
}

export const QUAD_VS = `#version 300 es
precision highp float;
layout(location=0) in vec2 a_pos;
layout(location=1) in vec2 a_uv;
layout(location=2) in vec4 a_color;
uniform vec2 u_resolution;
out vec2 v_uv;
out vec4 v_color;
void main() {
  vec2 ndc = (a_pos / u_resolution) * 2.0 - 1.0;
  ndc.y = -ndc.y;
  gl_Position = vec4(ndc, 0.0, 1.0);
  v_uv = a_uv;
  v_color = a_color;
}`;

export const QUAD_FS = `#version 300 es
precision highp float;
in vec2 v_uv;
in vec4 v_color;
uniform sampler2D u_tex;
uniform int u_alphaMode;
out vec4 fragColor;
void main() {
  vec4 c = texture(u_tex, v_uv) * v_color;
  if (u_alphaMode == 1 && c.a < 0.5) discard;
  fragColor = c;
}`;

export const TILED_FS = `#version 300 es
precision highp float;
in vec2 v_uv;
in vec4 v_color;
uniform sampler2D u_tex;
uniform vec2 u_quadSize;
uniform vec2 u_tileSize;
uniform int u_alphaMode;
out vec4 fragColor;
void main() {
  vec2 tiledUV = fract(v_uv * (u_quadSize / u_tileSize));
  vec4 c = texture(u_tex, tiledUV) * v_color;
  if (u_alphaMode == 1 && c.a < 0.5) discard;
  fragColor = c;
}`;

export const ELLIPSE_FS = `#version 300 es
precision highp float;
in vec2 v_uv;
in vec4 v_color;
uniform sampler2D u_tex;
uniform vec2 u_ellipseCenter;
uniform vec2 u_ellipseRadius;
uniform float u_uvOffset;
out vec4 fragColor;
void main() {
  vec2 scrolledUV = vec2(v_uv.x + u_uvOffset, v_uv.y);
  scrolledUV.x = fract(scrolledUV.x);
  vec4 c = texture(u_tex, scrolledUV) * v_color;
  vec2 d = (v_uv - u_ellipseCenter) / u_ellipseRadius;
  if (dot(d, d) > 1.0) discard;
  fragColor = c;
}`;

import { QUAD_VS, QUAD_FS, TILED_FS, ELLIPSE_FS } from './shaders';

function compileShader(gl: WebGL2RenderingContext, type: number, src: string): WebGLShader | null {
  const s = gl.createShader(type)!;
  gl.shaderSource(s, src);
  gl.compileShader(s);
  if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
    console.error('Shader:', gl.getShaderInfoLog(s));
    gl.deleteShader(s);
    return null;
  }
  return s;
}

function createProgram(gl: WebGL2RenderingContext, vsSrc: string, fsSrc: string): WebGLProgram | null {
  const vs = compileShader(gl, gl.VERTEX_SHADER, vsSrc);
  const fs = compileShader(gl, gl.FRAGMENT_SHADER, fsSrc);
  if (!vs || !fs) return null;
  const p = gl.createProgram()!;
  gl.attachShader(p, vs);
  gl.attachShader(p, fs);
  gl.linkProgram(p);
  if (!gl.getProgramParameter(p, gl.LINK_STATUS)) {
    console.error('Program:', gl.getProgramInfoLog(p));
    return null;
  }
  return p;
}

export interface ProgramLocs {
  resolution: WebGLUniformLocation | null;
  tex: WebGLUniformLocation | null;
  alphaMode: WebGLUniformLocation | null;
}

export interface TiledLocs extends ProgramLocs {
  quadSize: WebGLUniformLocation | null;
  tileSize: WebGLUniformLocation | null;
}

export interface EllipseLocs {
  resolution: WebGLUniformLocation | null;
  tex: WebGLUniformLocation | null;
  ellipseCenter: WebGLUniformLocation | null;
  ellipseRadius: WebGLUniformLocation | null;
  uvOffset: WebGLUniformLocation | null;
}

export class GLContext {
  gl!: WebGL2RenderingContext;
  canvas!: HTMLCanvasElement;
  canvasW = 0;
  canvasH = 0;
  dpr = 1;

  quadProg!: WebGLProgram;
  tiledProg!: WebGLProgram;
  ellipseProg!: WebGLProgram;

  quadLocs!: ProgramLocs;
  tiledLocs!: TiledLocs;
  ellipseLocs!: EllipseLocs;

  private resizeHandler = () => this.resize();

  init(canvas: HTMLCanvasElement) {
    this.canvas = canvas;
    this.gl = canvas.getContext('webgl2', {
      alpha: true,
      premultipliedAlpha: false,
      antialias: false,
      depth: false,
      stencil: true,
    })!;

    const gl = this.gl;

    this.quadProg = createProgram(gl, QUAD_VS, QUAD_FS)!;
    this.tiledProg = createProgram(gl, QUAD_VS, TILED_FS)!;
    this.ellipseProg = createProgram(gl, QUAD_VS, ELLIPSE_FS)!;

    this.quadLocs = {
      resolution: gl.getUniformLocation(this.quadProg, 'u_resolution'),
      tex: gl.getUniformLocation(this.quadProg, 'u_tex'),
      alphaMode: gl.getUniformLocation(this.quadProg, 'u_alphaMode'),
    };
    this.tiledLocs = {
      resolution: gl.getUniformLocation(this.tiledProg, 'u_resolution'),
      tex: gl.getUniformLocation(this.tiledProg, 'u_tex'),
      quadSize: gl.getUniformLocation(this.tiledProg, 'u_quadSize'),
      tileSize: gl.getUniformLocation(this.tiledProg, 'u_tileSize'),
      alphaMode: gl.getUniformLocation(this.tiledProg, 'u_alphaMode'),
    };
    this.ellipseLocs = {
      resolution: gl.getUniformLocation(this.ellipseProg, 'u_resolution'),
      tex: gl.getUniformLocation(this.ellipseProg, 'u_tex'),
      ellipseCenter: gl.getUniformLocation(this.ellipseProg, 'u_ellipseCenter'),
      ellipseRadius: gl.getUniformLocation(this.ellipseProg, 'u_ellipseRadius'),
      uvOffset: gl.getUniformLocation(this.ellipseProg, 'u_uvOffset'),
    };

    this.resize();
    window.addEventListener('resize', this.resizeHandler);
  }

  resize() {
    this.dpr = window.devicePixelRatio || 1;
    this.canvasW = window.innerWidth;
    this.canvasH = window.innerHeight;
    this.canvas.width = this.canvasW * this.dpr;
    this.canvas.height = this.canvasH * this.dpr;
    this.canvas.style.width = this.canvasW + 'px';
    this.canvas.style.height = this.canvasH + 'px';
    this.gl.viewport(0, 0, this.canvas.width, this.canvas.height);
  }

  destroy() {
    window.removeEventListener('resize', this.resizeHandler);
  }
}

import type { GLContext } from './GLContext';
import type { QuadBatcher } from './QuadBatcher';

export type BlendMode = 'BLEND' | 'ADD' | 'NONE';

export class BlendManager {
  private current: BlendMode | '' = '';
  private ctx!: GLContext;
  private batcher!: QuadBatcher;
  currentProg: WebGLProgram | null = null;

  init(ctx: GLContext, batcher: QuadBatcher) {
    this.ctx = ctx;
    this.batcher = batcher;
  }

  setBlend(mode: BlendMode) {
    if (mode === this.current) return;
    this.batcher.flush();
    this.current = mode;
    const gl = this.ctx.gl;
    switch (mode) {
      case 'BLEND':
        gl.enable(gl.BLEND);
        gl.blendFunc(gl.SRC_ALPHA, gl.ONE_MINUS_SRC_ALPHA);
        break;
      case 'ADD':
        gl.enable(gl.BLEND);
        gl.blendFunc(gl.SRC_ALPHA, gl.ONE);
        break;
      case 'NONE':
        gl.disable(gl.BLEND);
        break;
    }
  }

  useProgram(prog: WebGLProgram) {
    if (prog !== this.currentProg) {
      this.batcher.flush();
      this.currentProg = prog;
      this.ctx.gl.useProgram(prog);
    }
  }
}

import type { TextureEntry } from '../lib/types';
import type { GLContext } from './GLContext';

const MAX_QUADS = 1024;
const FLOATS_PER_VERTEX = 8; // x, y, u, v, r, g, b, a
const VERTS_PER_QUAD = 6;

export class QuadBatcher {
  private buf = new Float32Array(MAX_QUADS * VERTS_PER_QUAD * FLOATS_PER_VERTEX);
  private count = 0;
  batchTex: WebGLTexture | null = null;

  private vao!: WebGLVertexArrayObject;
  private vbo!: WebGLBuffer;
  private ctx!: GLContext;

  init(ctx: GLContext) {
    this.ctx = ctx;
    const gl = ctx.gl;

    this.vao = gl.createVertexArray()!;
    this.vbo = gl.createBuffer()!;
    gl.bindVertexArray(this.vao);
    gl.bindBuffer(gl.ARRAY_BUFFER, this.vbo);
    gl.bufferData(gl.ARRAY_BUFFER, this.buf.byteLength, gl.DYNAMIC_DRAW);
    gl.enableVertexAttribArray(0);
    gl.vertexAttribPointer(0, 2, gl.FLOAT, false, FLOATS_PER_VERTEX * 4, 0);
    gl.enableVertexAttribArray(1);
    gl.vertexAttribPointer(1, 2, gl.FLOAT, false, FLOATS_PER_VERTEX * 4, 8);
    gl.enableVertexAttribArray(2);
    gl.vertexAttribPointer(2, 4, gl.FLOAT, false, FLOATS_PER_VERTEX * 4, 16);
    gl.bindVertexArray(null);
  }

  flush() {
    if (this.count === 0) return;
    const gl = this.ctx.gl;
    gl.bindVertexArray(this.vao);
    gl.bindBuffer(gl.ARRAY_BUFFER, this.vbo);
    gl.bufferSubData(gl.ARRAY_BUFFER, 0, this.buf.subarray(0, this.count * VERTS_PER_QUAD * FLOATS_PER_VERTEX));
    gl.drawArrays(gl.TRIANGLES, 0, this.count * VERTS_PER_QUAD);
    gl.bindVertexArray(null);
    this.count = 0;
  }

  private pushRaw(x: number, y: number, w: number, h: number,
    u0: number, v0: number, u1: number, v1: number,
    r: number, g: number, b: number, a: number) {
    if (this.count >= MAX_QUADS) this.flush();
    const i = this.count * VERTS_PER_QUAD * FLOATS_PER_VERTEX;
    const x2 = x + w, y2 = y + h;
    const buf = this.buf;
    buf[i]    = x;  buf[i+1]  = y;  buf[i+2]  = u0; buf[i+3]  = v0;
    buf[i+4]  = r;  buf[i+5]  = g;  buf[i+6]  = b;  buf[i+7]  = a;
    buf[i+8]  = x2; buf[i+9]  = y;  buf[i+10] = u1; buf[i+11] = v0;
    buf[i+12] = r;  buf[i+13] = g;  buf[i+14] = b;  buf[i+15] = a;
    buf[i+16] = x;  buf[i+17] = y2; buf[i+18] = u0; buf[i+19] = v1;
    buf[i+20] = r;  buf[i+21] = g;  buf[i+22] = b;  buf[i+23] = a;
    buf[i+24] = x2; buf[i+25] = y;  buf[i+26] = u1; buf[i+27] = v0;
    buf[i+28] = r;  buf[i+29] = g;  buf[i+30] = b;  buf[i+31] = a;
    buf[i+32] = x2; buf[i+33] = y2; buf[i+34] = u1; buf[i+35] = v1;
    buf[i+36] = r;  buf[i+37] = g;  buf[i+38] = b;  buf[i+39] = a;
    buf[i+40] = x;  buf[i+41] = y2; buf[i+42] = u0; buf[i+43] = v1;
    buf[i+44] = r;  buf[i+45] = g;  buf[i+46] = b;  buf[i+47] = a;
    this.count++;
  }

  drawQuad(x: number, y: number, w: number, h: number,
    texEntry: TextureEntry | null,
    u0: number, v0: number, u1: number, v1: number,
    r = 1, g = 1, b = 1, a = 1) {
    const gl = this.ctx.gl;
    const whiteTex = (this.ctx as any)._texManager?.whiteTex;
    const t = texEntry ? texEntry.tex : (whiteTex || null);
    if (t !== this.batchTex) {
      this.flush();
      this.batchTex = t;
      gl.activeTexture(gl.TEXTURE0);
      gl.bindTexture(gl.TEXTURE_2D, t);
    }
    const dpr = this.ctx.dpr;
    this.pushRaw(x * dpr, y * dpr, w * dpr, h * dpr, u0, v0, u1, v1, r, g, b, a);
  }

  drawQuadRotated(x: number, y: number, w: number, h: number,
    texEntry: TextureEntry | null,
    u0: number, v0: number, u1: number, v1: number) {
    const gl = this.ctx.gl;
    const whiteTex = (this.ctx as any)._texManager?.whiteTex;
    const t = texEntry ? texEntry.tex : (whiteTex || null);
    if (t !== this.batchTex) {
      this.flush();
      this.batchTex = t;
      gl.activeTexture(gl.TEXTURE0);
      gl.bindTexture(gl.TEXTURE_2D, t);
    }
    if (this.count >= MAX_QUADS) this.flush();
    const dpr = this.ctx.dpr;
    const px = x * dpr, py = y * dpr, pw = w * dpr, ph = h * dpr;
    const x2 = px + pw, y2 = py + ph;
    const i = this.count * VERTS_PER_QUAD * FLOATS_PER_VERTEX;
    const r = 1, g = 1, b = 1, a = 1;
    const buf = this.buf;
    buf[i]    = px; buf[i+1]  = py; buf[i+2]  = u0; buf[i+3]  = v1;
    buf[i+4]  = r;  buf[i+5]  = g;  buf[i+6]  = b;  buf[i+7]  = a;
    buf[i+8]  = x2; buf[i+9]  = py; buf[i+10] = u0; buf[i+11] = v0;
    buf[i+12] = r;  buf[i+13] = g;  buf[i+14] = b;  buf[i+15] = a;
    buf[i+16] = px; buf[i+17] = y2; buf[i+18] = u1; buf[i+19] = v1;
    buf[i+20] = r;  buf[i+21] = g;  buf[i+22] = b;  buf[i+23] = a;
    buf[i+24] = x2; buf[i+25] = py; buf[i+26] = u0; buf[i+27] = v0;
    buf[i+28] = r;  buf[i+29] = g;  buf[i+30] = b;  buf[i+31] = a;
    buf[i+32] = x2; buf[i+33] = y2; buf[i+34] = u1; buf[i+35] = v0;
    buf[i+36] = r;  buf[i+37] = g;  buf[i+38] = b;  buf[i+39] = a;
    buf[i+40] = px; buf[i+41] = y2; buf[i+42] = u1; buf[i+43] = v1;
    buf[i+44] = r;  buf[i+45] = g;  buf[i+46] = b;  buf[i+47] = a;
    this.count++;
  }
}

import type { TextureEntry } from '../lib/types';

export class TextureManager {
  private cache = new Map<string, TextureEntry>();
  whiteTex!: WebGLTexture;
  private gl!: WebGL2RenderingContext;

  init(gl: WebGL2RenderingContext) {
    this.gl = gl;
    this.whiteTex = gl.createTexture()!;
    gl.bindTexture(gl.TEXTURE_2D, this.whiteTex);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE,
      new Uint8Array([255, 255, 255, 255]));
  }

  load(path: string): TextureEntry {
    if (this.cache.has(path)) return this.cache.get(path)!;
    const gl = this.gl;
    const tex = gl.createTexture()!;
    gl.bindTexture(gl.TEXTURE_2D, tex);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE,
      new Uint8Array([255, 255, 255, 255]));
    const entry: TextureEntry = { tex, width: 1, height: 1, loaded: false };
    this.cache.set(path, entry);
    const img = new Image();
    img.onload = () => {
      gl.bindTexture(gl.TEXTURE_2D, tex);
      gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, img);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
      entry.width = img.width;
      entry.height = img.height;
      entry.loaded = true;
    };
    img.src = path;
    return entry;
  }

  loadRepeat(path: string): TextureEntry {
    const key = path + '?repeat';
    if (this.cache.has(key)) return this.cache.get(key)!;
    const gl = this.gl;
    const tex = gl.createTexture()!;
    gl.bindTexture(gl.TEXTURE_2D, tex);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, 1, 1, 0, gl.RGBA, gl.UNSIGNED_BYTE,
      new Uint8Array([255, 255, 255, 255]));
    const entry: TextureEntry = { tex, width: 1, height: 1, loaded: false };
    this.cache.set(key, entry);
    const img = new Image();
    img.onload = () => {
      gl.bindTexture(gl.TEXTURE_2D, tex);
      gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, img);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.REPEAT);
      gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.REPEAT);
      entry.width = img.width;
      entry.height = img.height;
      entry.loaded = true;
    };
    img.src = path;
    return entry;
  }

  get(path: string): WebGLTexture {
    const e = this.cache.get(path);
    return e ? e.tex : this.whiteTex;
  }

  preload(paths: string[]) {
    paths.forEach(p => this.load(p));
  }
}

import type { TextureEntry } from '../lib/types';
import type { GLContext } from './GLContext';
import type { QuadBatcher } from './QuadBatcher';
import type { BlendManager } from './BlendManager';

export function drawNineSlice(
  ctx: GLContext,
  batcher: QuadBatcher,
  blend: BlendManager,
  x: number, y: number, w: number, h: number,
  borderEntry: TextureEntry | null,
  cornerSize: number,
  tiledBgEntry: TextureEntry | null,
  tileSize: number,
  inset?: number
) {
  if (!borderEntry || !borderEntry.loaded) return;
  const gl = ctx.gl;
  const atlasW = borderEntry.width;
  const cellW = atlasW / 8;
  const cs = cornerSize;
  const ins = inset || 0;

  function cellUV(idx: number): [number, number, number, number] {
    const u0 = (idx * cellW) / atlasW;
    const u1 = ((idx + 1) * cellW) / atlasW;
    return [u0, 0, u1, 1];
  }

  // Tiled background
  if (tiledBgEntry && tiledBgEntry.loaded) {
    batcher.flush();
    blend.useProgram(ctx.tiledProg);
    gl.uniform2f(ctx.tiledLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
    gl.uniform1i(ctx.tiledLocs.tex, 0);
    gl.uniform2f(ctx.tiledLocs.quadSize, w - ins * 2, h - ins * 2);
    gl.uniform2f(ctx.tiledLocs.tileSize, tileSize, tileSize);
    gl.uniform1i(ctx.tiledLocs.alphaMode, 0);
    blend.setBlend('BLEND');
    batcher.batchTex = null;
    batcher.drawQuad(x + ins, y + ins, w - ins * 2, h - ins * 2, tiledBgEntry, 0, 0, 1, 1);
    batcher.flush();
    blend.useProgram(ctx.quadProg);
    gl.uniform2f(ctx.quadLocs.resolution, ctx.canvasW * ctx.dpr, ctx.canvasH * ctx.dpr);
    gl.uniform1i(ctx.quadLocs.tex, 0);
    gl.uniform1i(ctx.quadLocs.alphaMode, 0);
    batcher.batchTex = null;
  }

  blend.setBlend('BLEND');

  // Corners
  const [u4a, v4a, u4b, v4b] = cellUV(4);
  batcher.drawQuad(x, y, cs, cs, borderEntry, u4a, v4a, u4b, v4b);
  const [u5a, v5a, u5b, v5b] = cellUV(5);
  batcher.drawQuad(x + w - cs, y, cs, cs, borderEntry, u5a, v5a, u5b, v5b);
  const [u6a, v6a, u6b, v6b] = cellUV(6);
  batcher.drawQuad(x, y + h - cs, cs, cs, borderEntry, u6a, v6a, u6b, v6b);
  const [u7a, v7a, u7b, v7b] = cellUV(7);
  batcher.drawQuad(x + w - cs, y + h - cs, cs, cs, borderEntry, u7a, v7a, u7b, v7b);

  // Vertical edges
  const edgeH = h - cs * 2;
  if (edgeH > 0) {
    const [u0a, v0a, u0b, v0b] = cellUV(0);
    batcher.drawQuad(x, y + cs, cs, edgeH, borderEntry, u0a, v0a, u0b, v0b);
    const [u1a, v1a, u1b, v1b] = cellUV(1);
    batcher.drawQuad(x + w - cs, y + cs, cs, edgeH, borderEntry, u1a, v1a, u1b, v1b);
  }

  // Horizontal edges (rotated)
  const edgeW = w - cs * 2;
  if (edgeW > 0) {
    const [u2a, v2a, u2b, v2b] = cellUV(2);
    batcher.drawQuadRotated(x + cs, y, edgeW, cs, borderEntry, u2a, v2a, u2b, v2b);
    const [u3a, v3a, u3b, v3b] = cellUV(3);
    batcher.drawQuadRotated(x + cs, y + h - cs, edgeW, cs, borderEntry, u3a, v3a, u3b, v3b);
  }
}

