import { onMount, type Accessor } from 'solid-js';
import type { Renderer } from '../renderer/Renderer';

interface Props {
  label: string;
  type: 'health' | 'mana' | 'xp' | 'build';
  fillPercent: Accessor<number>;
  maxValue?: number;
  height?: number;
  hasBorder?: boolean;
  renderer: Renderer;
}

export default function StatBar(props: Props) {
  let ref!: HTMLDivElement;

  onMount(() => {
    props.renderer.statBars.push({
      ref: () => ref,
      fillPercent: props.fillPercent,
      type: props.type,
      hasBorder: !!props.hasBorder,
    });
  });

  const barText = () => {
    const pct = props.fillPercent();
    if (props.type === 'build') return pct + '%';
    if (props.maxValue) {
      return Math.floor(props.maxValue * pct / 100) + '\u00a0/ ' + props.maxValue;
    }
    return pct + '%';
  };

  return (
    <div class="bar-row">
      <span class="bar-label">{props.label}</span>
      <div ref={ref} class="stat-bar" style={{ height: (props.height || 18) + 'px' }}>
        <div
          class={`bar-fill-img ${props.type}-fill animated-bar`}
          style={{ width: props.fillPercent() + '%' }}
        />
        {props.hasBorder && <img class="bar-border-overlay" src="" alt="" />}
        <div class="bar-text" style={props.height && props.height < 18 ? { 'font-size': '0.6rem' } : {}}>
          {barText()}
        </div>
      </div>
    </div>
  );
}

