    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    renderer.loadRace(race);
  }, [renderer, race]);

  return (
    <WC3RendererContext.Provider value={{ renderer }}>
      <canvas
        ref={canvasRef}
        className={canvasClassName}
        style={{
          position: 'fixed',
          inset: 0,
          width: '100%',
          height: '100%',
          pointerEvents: 'none',
          zIndex: 0,
        }}
      />
      {children}
    </WC3RendererContext.Provider>
  );
}

