import { createContext, useContext, useEffect, useRef, type ReactNode } from 'react';
import { Renderer, type Race } from '@wc3-ui/core';

interface WC3RendererContextValue {
  renderer: Renderer;
}

const WC3RendererContext = createContext<WC3RendererContextValue | null>(null);

export interface WC3RendererProviderProps {
  children: ReactNode;
  /** Initial race to load textures for. Defaults to 'Human'. */
  race?: Race;
  /** CSS class for the overlay canvas */
  canvasClassName?: string;
}

export function WC3RendererProvider({ children, race = 'Human', canvasClassName }: WC3RendererProviderProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rendererRef = useRef<Renderer | null>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const renderer = new Renderer();
    rendererRef.current = renderer;
    renderer.init(canvas);
    renderer.loadRace(race);
    renderer.preloadAll();
    renderer.start();

    return () => {
      renderer.destroy();
      rendererRef.current = null;
    };
  }, []);

  useEffect(() => {
    rendererRef.current?.loadRace(race);
  }, [race]);

  // We need a stable renderer instance to pass via context even before init.
  // Create it once on first render (not in effect) so children's effects can
  // register with it immediately. The canvas init happens in the effect above.
  if (!rendererRef.current) {
    rendererRef.current = new Renderer();
  }

  return (
    <WC3RendererContext.Provider value={{ renderer: rendererRef.current }}>
      <canvas
        ref={canvasRef}
        className={canvasClassName}
        style={{
          position: 'fixed',
          inset: 0,
          width: '100%',
          height: '100%',
          pointerEvents: 'none',
          zIndex: 0,
        }}
      />
      {children}
    </WC3RendererContext.Provider>
  );
}

export function useWC3Renderer(): Renderer {
  const ctx = useContext(WC3RendererContext);
  if (!ctx) {
    throw new Error('useWC3Renderer must be used inside <WC3RendererProvider>');
  }
  return ctx.renderer;
}

